import {
  HttpEvent,
  HttpHandler,
  HttpInterceptor,
  HttpRequest,
  HttpErrorResponse,
} from '@angular/common/http';
import { Observable, throwError } from 'rxjs';
import { catchError, tap } from 'rxjs/operators';

const EXTERNAL_APIS = ['viacep', 'googleapis'];

/**
 * Platform-agnostic auth/error interceptor skeleton shared by web + app.
 * Subclasses inject their own AuthService/alert facilities and override the
 * template hooks; the common pipeline (auth header, known error-code dispatch,
 * error surfacing) lives here once.
 */
export abstract class BaseAuthInterceptor implements HttpInterceptor {
  /** Current user token, or undefined when anonymous. */
  protected abstract token(): string | undefined;

  /** Authorization header prefix (web: `Bearer `, app: ``). */
  protected readonly authScheme: string = '';

  /** Platform reaction to a known backend error `code` (banned / token_expired / …). */
  protected abstract onErrorCode(code: string, error: HttpErrorResponse): void;

  /** Surface a backend error message to the user. */
  protected abstract showError(message: string | null): void;

  /** Cache/storage short-circuit (web). Return a stream to skip `next.handle`. */
  protected shortCircuit(
    request: HttpRequest<unknown>,
  ): Observable<HttpEvent<unknown>> | null {
    return null;
  }

  /** Per-request mutation hook (SSR headers, query params). */
  protected prepare(request: HttpRequest<unknown>): HttpRequest<unknown> {
    return request;
  }

  /* eslint-disable-next-line @typescript-eslint/no-empty-function */
  protected onResponse(_event: HttpEvent<unknown>, _request: HttpRequest<unknown>): void {}

  protected isExternalApi(url: string): boolean {
    return EXTERNAL_APIS.some((api) => url.includes(api));
  }

  intercept(
    request: HttpRequest<unknown>,
    next: HttpHandler,
  ): Observable<HttpEvent<unknown>> {
    const short = this.shortCircuit(request);
    if (short) return short;

    const token = this.token();
    if (token && !this.isExternalApi(request.url)) {
      request = request.clone({
        headers: request.headers.set(
          'Authorization',
          `${this.authScheme}${token}`,
        ),
      });
    }

    request = this.prepare(request);

    return next.handle(request).pipe(
      tap((event) => this.onResponse(event, request)),
      catchError((error: HttpErrorResponse) => {
        const code = error.error?.code;
        if (code) this.onErrorCode(code, error);
        this.showError(error.error?.message ?? null);
        return throwError(() => error.error);
      }),
    );
  }
}

import { BasicModel } from './basic';
import { Brand } from './brands';
import { ClothesStatus } from './clothes-status';

export interface ClothesImage {
  _id: string;
  sm: string;
  md: string;
  lg: string;
}

export class Clothes {
  // properties
  _id?: string;
  /** Server-provided image variants returned by the API with resolveImages=true. */
  images: ClothesImage[];
  /** Legacy field – kept only for backward-compat; prefer `images`. */
  pictures?: { url: string }[];
  /** Legacy field – kept only for backward-compat; prefer `images[0]`. */
  smallPicture?: { url: string };
  title!: string;
  description!: string;
  refund?: boolean;
  condition!: number;
  category!: number;
  gender!: number;
  special!: number;
  piece!: number;
  size!: number;
  cost!: number;
  firstCost?: number;
  age!: number;
  sell: boolean;
  weight!: number;
  declaredValue?: boolean;
  owner?: string;
  status?: ClothesStatus;
  adjusts: number[];
  adjustsNote!: string;
  questions?: { _id: string; question: string; answer?: string; questioner?: string }[];
  copyOf?: string;
  createdAt?: Date;
  updatedAt?: Date;
  brand?: Brand;
  __v!: number;
  reserve?: { reservedBy: string; reservedAt: Date };
  expiresAt?: Date;
  viewCount?: number;
  favoritedCount?: number;
  costHistory?: { cost: number; changedAt: Date }[];
  newImages?: boolean;

  constructor(init?: Partial<Clothes>) {
    this.images = [];
    this.adjusts = [];
    this.sell = false;

    if (init) Object.assign(this, init);
  }

  // methods
  get waitingAdjustment() {
    return this.status === ClothesStatus.WAITING_ADJUSTMENT;
  }

  get waitingPublication() {
    return this.status === ClothesStatus.WAITING_PUBLICATION;
  }

  get reserved() {
    return this.status === ClothesStatus.RESERVED;
  }

  get published() {
    return this.status === ClothesStatus.PUBLISHED;
  }

  get sold() {
    return this.status === ClothesStatus.SOLD;
  }

  get selling() {
    return this.status === ClothesStatus.NEGOTIATING_SELL;
  }

  get expired() {
    return this.status === ClothesStatus.EXPIRED;
  }

  get unavailable() {
    return (
      this.status === ClothesStatus.ANALYSIS_REPROVED ||
      this.status === ClothesStatus.DELETED_BY_USER
    );
  }

  get paused() {
    return this.status === ClothesStatus.PAUSED_BY_USER;
  }

  get statusFormatted() {
    if (this.waitingAdjustment) return 'Requer ajustes';
    if (this.waitingPublication) return 'Em análise';
    if (this.expired) return 'Expirado';
    if (this.sold) return 'Vendido';
    if (this.reserved || this.selling) return 'Reservado';
    if (this.unavailable) return 'Indisponível';
    if (this.paused) return 'Pausado';

    return '';
  }

  get mainImage(): string | undefined {
    return this.images[0]?.md ?? this.smallPicture?.url;
  }

  get thumbnailUrl(): string | undefined {
    return this.images[0]?.sm ?? this.smallPicture?.url;
  }
}

